var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"주인님을 방해하는 어리석은 자들......","JPN":"マスターを邪魔する愚かな奴ら……","ENG":"You fools dare to disturb the Master...","TWN":"防礙主人的愚蠢的傢伙……"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"주인님의 충실한 인형인 내가...... 너희를 벌하겠다......","JPN":"マスターの忠実な人形である私が……お前たちを罰する……","ENG":"As her loyal puppet... I will punish you...","TWN":"我作為主人忠實的木偶……要懲罰你們……"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"정신 차려, 잉그리드!","JPN":"しっかりしろ、イングリッド！","ENG":"Snap out of it, Ingrid!","TWN":"振作點啊，英格麗！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"최강의 마녀가 되겠다던 녀석이 그깟 저주에 정신 못 차리는 거야?!","JPN":"最強の魔女になると言ってた奴がその程度の呪いで正気を失うのか？","ENG":"It's just a stupid curse! What happened to becoming the greatest witch ever?","TWN":"妳說妳要成為最強魔女，妳怎麼可以向那種詛咒低頭呢？！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그만둬, 라우라. 지금 잉그리드에겐 우리 목소리가 전혀 들리지 않을 거야.","JPN":"やめてラウラ。今のイングリッドには私たちの声が全然聞こえないはず。","ENG":"That's enough, Laura. Ingrid probably can't hear us at all.","TWN":"算了，蘿拉。現在英格麗聽不到的。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"나도 알아. 그냥...... 확인해 봤을 뿐이야.","JPN":"妾も知ってる。ただ……確かめてみただけだ。","ENG":"I know. I just... wanted to check.","TWN":"我也知道。只是……我想確認一下。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"생각해 보면...... 난 정말 멍청하게 굴었어.","JPN":"思い返してみれば……私は本当にバカだった。","ENG":"Come to think of it, I've been so stupid.","TWN":"之前……我為什麼會那麼蠢？"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"대체 왜 고작 정식 마녀가 되겠다고 그렇게 노력했던 걸까?","JPN":"いったいなんで正式な魔女なんかになろうとあんなに頑張ってきたんだろう？","ENG":"Why did I bust my butt trying to become a witch?","TWN":"為什麼非要成為正式魔女呢？"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"이렇게 주인님의 인형이 되는 것만으로도......","JPN":"こうしてマスターのお人形になるだけで……","ENG":"All I needed was to become the Master's puppet...","TWN":"明明成為主人的木偶……"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"진정한 마녀가 될 수 있는데 말이야.","JPN":"真の魔女になれるのに……","ENG":"To become a true witch.","TWN":"也可以成為真正的魔女。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"......맛이 간 상태에서도 제멋대로네. 누가 정식 마녀로 인정해 주기나 한대?","JPN":"……正気を失っているのに自分勝手なのは相変わらずだな。\\n汝を正式な魔女に認めた覚えはない。","ENG":"She's still out of whack even while she's brainwashed. Whoever said she's a real witch now?","TWN":"……都那個樣子了居然還是那麼任性。誰承認過妳是正式魔女了？"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그것보다 잉그리드에게서 흘러나오는 마력이 심상치 않아.","JPN":"それよりもイングリッドから溢れ出る魔力が尋常じゃないわ。","ENG":"Forget about that. The mana coming from Ingrid is most worrisome.","TWN":"英格麗散發的魔力不同尋常啊。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"혼자선 감당하기 어려울 정도야. 저대로 두면 폭주하는 힘 때문에 몸이 남아나지 않겠어.","JPN":"一人じゃ手に負えないほどよ。あのままにしておくと\\n暴走する力のせいで体がもたないわ。","ENG":"She's not going to be able to handle that much mana. At this rate, it will tear her body apart.","TWN":"她自己是難以承受的。這樣下去，很有可能被爆發的力量傷到的。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그리고 그런 식으로 성 여기저기에 마력을 폭발시켜서 남은 결계도 무너뜨릴 속셈이겠지.","JPN":"城のいたる場所であの魔力を爆発させて、残った結界も破る気だろうな。","ENG":"I guess the Puppet Master's plan is to explode the mana everywhere across the castle to tear down the remaining barrier.","TWN":"她估計是想用那種方式，在城的各處爆發魔力，然後打破剩下的結界。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"예전이랑 레퍼토리가 똑같잖아. 인형 극단이라더니 공연도 보나마나 3류겠어.","JPN":"前と同じ流れじゃないか。人形劇団といってるが、どうせ三流公演だろう。","ENG":"It's the same old routine! I bet her stupid puppet show is just as predictable.","TWN":"手段和以前一模一樣。木偶劇團？不用看就知道是個不入流的。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그만큼 잘 먹힌다는 뜻이겠지.","JPN":"それほど効いてるってことね。","ENG":"Well, it must also mean that it's a tried-and-true method.","TWN":"也可以理解為這個方法很好用。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"서둘러 막지 않으면 돌이킬 수 없을 거야.","JPN":"急いで阻止しないと取り返しのつかないことになるわ。","ENG":"If we don't stop her soon, there will be no going back.","TWN":"如果不快點阻止她，後果將不堪設想。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"너희들은 주인님의 일을 방해하러 온 거겠지?","JPN":"お前たちはマスターの仕事を邪魔しに来たんだろう？","ENG":"You must be here to disrupt the Master's plans.","TWN":"妳們是不是來妨礙主人的？"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"그런 건...... 용납할 수 없어!","JPN":"そんなこと……許さない！","ENG":"I won't let you!","TWN":"我……絕不允許！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"온다! 엄호 부탁해!","JPN":"来る！　援護を頼む！","ENG":"Here she comes! Cover me!","TWN":"過來了！快掩護我！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"내게 맡겨!","JPN":"私に任せて！","ENG":"Got it!","TWN":"交給我！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};